package connectors.livelink.connector.org.apache.manifoldcf.crawler.connectors.livelink;

protected static class EvaluatorTokenStream { protected String text ; protected int pos ; protected EvaluatorToken token = null ; public EvaluatorTokenStream ( String text ) { this . text = text ; this . pos = 0 ; } public EvaluatorToken peek ( ) { if ( token == null ) { token = nextToken ( ) ; } return token ; } public void advance ( ) { token = null ; } protected EvaluatorToken nextToken ( ) { char x ; while ( true ) { if ( pos == text . length ( ) ) return null ; x = text . charAt ( pos ) ; if ( x > ' ' ) break ; pos ++ ; } StringBuilder sb ; if ( x == '"' ) { pos ++ ; sb = new StringBuilder ( ) ; while ( true ) { if ( pos == text . length ( ) ) break ; x = text . charAt ( pos ) ; pos ++ ; if ( x == '"' ) { break ; } if ( x == '\\' ) { if ( pos == text . length ( ) ) break ; x = text . charAt ( pos ++ ) ; } sb . append ( x ) ; } return new EvaluatorToken ( sb . toString ( ) ) ; } if ( x == ',' ) { pos ++ ; return new EvaluatorToken ( ) ; } sb = new StringBuilder ( ) ; while ( true ) { if ( pos == text . length ( ) ) break ; x = text . charAt ( pos ) ; if ( x >= '0' && x <= '9' ) { sb . append ( x ) ; pos ++ ; continue ; } break ; } String numberValue = sb . toString ( ) ; int groupNumber = 0 ; if ( numberValue . length ( ) > 0 ) groupNumber = new Integer ( numberValue ) . intValue ( ) ; int modifierPos = pos ; while ( true ) { if ( pos == text . length ( ) ) break ; x = text . charAt ( pos ) ; if ( x == ',' || x >= '0' && x <= '9' || x <= ' ' && x >= 0 ) break ; pos ++ ; } int style = EvaluatorToken . GROUPSTYLE_NONE ; if ( modifierPos != pos ) { String modifier = text . substring ( modifierPos , pos ) ; if ( modifier . startsWith ( "u" ) ) style = EvaluatorToken . GROUPSTYLE_UPPER ; else if ( modifier . startsWith ( "l" ) ) style = EvaluatorToken . GROUPSTYLE_LOWER ; else if ( modifier . startsWith ( "m" ) ) style = EvaluatorToken . GROUPSTYLE_MIXED ; } return new EvaluatorToken ( groupNumber , style ) ; } }